def bsearch_range_value_table(cp: int, r: list):
    """
    在范围表 r 中二分查找字符 c 所属的范围。
    r 的元素为 (lo, hi, cat)，其中 lo 和 hi 是 Unicode 码点（整数）。
    返回 cat。
    """
    lo = 0
    hi = len(r)

    while lo < hi:
        mid = (lo + hi) // 2
        lo_cp, hi_cp, cat = r[mid]
        if lo_cp <= cp <= hi_cp:
            # 精确命中
            return cat
        elif hi_cp < cp:
            # 当前范围在目标左边 -> 元素小于目标
            lo = mid + 1
        else:  # cp < lo_cp
            # 当前范围在目标右边 -> 元素大于目标
            hi = mid

    return 1  # WordCat.WC_Any


def word_category(cp: int) -> int:
    """
    返回字符 c 的 Unicode 单词分割类别信息：
    """
    lookup_interval = 0x80       # 128
    idx = cp // lookup_interval

    # 用预计算表定位要搜索的范围表切片
    if idx + 2 <= len(word_cat_lookup):   # 需要两个连续值
        start = word_cat_lookup[idx]
        end = word_cat_lookup[idx + 1] + 1   # 转为右开区间
    else:
        # 查表越界时使用默认切片（硬编码值来源于原 Rust 代码）
        start = 1097
        end = 1100

    r_slice = word_ranges[start:end]

    return bsearch_range_value_table(cp, r_slice)
